import React, { useState, useMemo } from 'react';
import {
    ComposableMap,
    Geographies,
    Geography,
    ZoomableGroup
} from 'react-simple-maps';
import { Page, PageTitle, Card, SectionTitle, TabBar, Select } from '../components/UI';
import data from '../data/trends.json';

const GEO_URL = '/india.json';

const GROUP_COLORS = {
    SC: '#64B5F6',
    ST: '#81C784',
    Women: '#FF7043',
    Children: '#FFB74D',
    Total: '#a78bfa',
};

const YEARS = ['2017', '2018', '2019', '2020', '2021', '2022'];
const GROUPS = ['Total', 'SC', 'ST', 'Women', 'Children'];

function normalizeName(name) {
    if (!name) return '';
    return name.toLowerCase().trim()
        .replace(/\s+/g, ' ')
        .replace(/&/g, 'and')
        .replace(/[^a-z0-9 ]/g, '');
}

function buildLookup(keys) {
    const lookup = {};
    keys.forEach(k => { lookup[normalizeName(k)] = k; });
    return lookup;
}

function hexToRgb(hex) {
    return [
        parseInt(hex.slice(1, 3), 16),
        parseInt(hex.slice(3, 5), 16),
        parseInt(hex.slice(5, 7), 16),
    ];
}

function getColor(value, maxVal, group) {
    if (!value || maxVal === 0) return 'rgba(255,255,255,0.04)';
    const intensity = Math.min(value / maxVal, 1);
    const [r, g, b] = hexToRgb(GROUP_COLORS[group] || '#a78bfa');
    const opacity = 0.12 + intensity * 0.88;
    return `rgba(${r},${g},${b},${opacity})`;
}

export default function Heatmap() {
    const [group, setGroup] = useState('Total');
    const [year, setYear] = useState('2022');
    const [tab, setTab] = useState('Map');
    const [tooltip, setTooltip] = useState(null);

    const heatmapData = data.heatmap || {};
    const lookup = useMemo(
        () => buildLookup(Object.keys(heatmapData)),
        [heatmapData]
    );

    function getValue(geoName) {
        const norm = normalizeName(geoName);
        // try direct match first
        let key = lookup[norm];
        // try partial match if not found
        if (!key) {
            key = Object.keys(heatmapData).find(k =>
                normalizeName(k).includes(norm) ||
                norm.includes(normalizeName(k))
            );
        }
        if (!key) return 0;
        return heatmapData[key]?.[group]?.[year] || 0;
    }

    const maxVal = useMemo(() => {
        const vals = Object.keys(heatmapData).map(k =>
            heatmapData[k]?.[group]?.[year] || 0
        );
        return Math.max(...vals, 1);
    }, [group, year, heatmapData]);

    const ranked = useMemo(() => {
        return Object.keys(heatmapData)
            .map(k => ({
                state: k,
                value: heatmapData[k]?.[group]?.[year] || 0
            }))
            .filter(s => s.value > 0)
            .sort((a, b) => b.value - a.value);
    }, [group, year, heatmapData]);

    const gc = GROUP_COLORS[group] || '#a78bfa';
    const [r, g, b] = hexToRgb(gc);

    return (
        <Page>
            <PageTitle
                title="🗺️ India Crime Heatmap"
                sub="State-wise crime intensity · Filter by group and year · 2017–2022"
            />

            {/* ── Filters ───────────────────────────────────────────── */}
            <Card style={{ marginBottom: 16 }}>
                <div style={{
                    display: 'grid',
                    gridTemplateColumns: '1fr 1fr',
                    gap: 14,
                }}>
                    <Select
                        label="Protected Group"
                        options={GROUPS}
                        value={group}
                        onChange={setGroup}
                    />
                    <Select
                        label="Year"
                        options={YEARS}
                        value={year}
                        onChange={setYear}
                    />
                </div>
            </Card>

            <TabBar
                tabs={['Map', 'Ranked List', 'Year Comparison']}
                active={tab}
                onChange={setTab}
            />

            {/* ── Tab 1: Map ────────────────────────────────────────── */}
            {tab === 'Map' && (
                <Card style={{ position: 'relative' }}>
                    <SectionTitle
                        title={`${group} Crimes · ${year}`}
                        sub="Darker = more crimes · Hover over a state to see details"
                    />

                    {/* Legend */}
                    <div style={{
                        display: 'flex', alignItems: 'center',
                        gap: 8, marginBottom: 12,
                    }}>
                        <span style={{ fontSize: 10, color: '#64748b' }}>Low</span>
                        <div style={{
                            display: 'flex', height: 10,
                            width: 180, borderRadius: 5, overflow: 'hidden',
                        }}>
                            {[...Array(10)].map((_, i) => (
                                <div key={i} style={{
                                    flex: 1,
                                    background: `rgba(${r},${g},${b},${0.12 + (i + 1) * 0.088})`,
                                }} />
                            ))}
                        </div>
                        <span style={{ fontSize: 10, color: '#64748b' }}>High</span>
                        <span style={{
                            fontSize: 10, color: '#64748b', marginLeft: 8,
                        }}>
                            Max: {maxVal.toFixed(1)} avg crimes/district
                        </span>
                    </div>

                    {/* Map */}
                    <div style={{
                        background: 'rgba(0,0,0,0.2)',
                        borderRadius: 12, overflow: 'hidden',
                    }}>
                        <ComposableMap
                            projection="geoMercator"
                            projectionConfig={{
                                center: [82, 22],
                                scale: 1000,
                            }}
                            style={{ width: '100%', height: 500 }}
                        >
                            <ZoomableGroup>
                                <Geographies geography={GEO_URL}>
                                    {({ geographies }) =>
                                        geographies.map(geo => {
                                            const name = geo.properties.NAME_1 ||
                                                geo.properties.name ||
                                                geo.properties.ST_NM ||
                                                geo.properties.state || '';
                                            const val = getValue(name);
                                            const color = getColor(val, maxVal, group);
                                            return (
                                                <Geography
                                                    key={geo.rsmKey}
                                                    geography={geo}
                                                    fill={color}
                                                    stroke="rgba(255,255,255,0.15)"
                                                    strokeWidth={0.5}
                                                    style={{
                                                        default: { outline: 'none' },
                                                        hover: {
                                                            outline: 'none',
                                                            fill: `rgba(${r},${g},${b},0.95)`,
                                                            stroke: '#ffffff',
                                                            strokeWidth: 1,
                                                            cursor: 'pointer',
                                                        },
                                                        pressed: { outline: 'none' },
                                                    }}
                                                    onMouseEnter={(evt) => {
                                                        setTooltip({
                                                            name,
                                                            value: val,
                                                            x: evt.clientX,
                                                            y: evt.clientY,
                                                        });
                                                    }}
                                                    onMouseMove={(evt) => {
                                                        setTooltip(t => t
                                                            ? { ...t, x: evt.clientX, y: evt.clientY }
                                                            : null
                                                        );
                                                    }}
                                                    onMouseLeave={() => setTooltip(null)}
                                                />
                                            );
                                        })
                                    }
                                </Geographies>
                            </ZoomableGroup>
                        </ComposableMap>
                    </div>

                    <div style={{
                        marginTop: 8, fontSize: 10,
                        color: '#475569', textAlign: 'center',
                    }}>
                        Scroll to zoom · Drag to pan ·
                        Values = avg crimes per district · Source: NCRB 2017–2022
                    </div>
                </Card>
            )}

            {/* ── Tab 2: Ranked List ────────────────────────────────── */}
            {tab === 'Ranked List' && (
                <Card>
                    <SectionTitle
                        title={`States Ranked · ${group} Crimes · ${year}`}
                        sub="Highest average crimes per district at the top"
                    />
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                        {ranked.map((item, i) => (
                            <div key={item.state} style={{
                                display: 'grid',
                                gridTemplateColumns: '28px 1fr auto',
                                gap: 10, alignItems: 'center',
                            }}>
                                <span style={{
                                    fontSize: 11,
                                    color: i < 3 ? gc : '#475569',
                                    fontWeight: 700, textAlign: 'right',
                                }}>
                                    {i + 1}
                                </span>
                                <div>
                                    <div style={{
                                        fontSize: 12,
                                        color: i < 3 ? '#f1f5f9' : '#94a3b8',
                                        marginBottom: 3,
                                        fontWeight: i < 3 ? 600 : 400,
                                    }}>
                                        {item.state}
                                    </div>
                                    <div style={{
                                        background: '#0b1120',
                                        borderRadius: 3, height: 5, overflow: 'hidden',
                                    }}>
                                        <div style={{
                                            width: `${(item.value / maxVal) * 100}%`,
                                            height: '100%',
                                            background: gc,
                                            borderRadius: 3, opacity: 0.8,
                                        }} />
                                    </div>
                                </div>
                                <span style={{
                                    fontSize: 13, fontWeight: 700,
                                    color: gc, minWidth: 50, textAlign: 'right',
                                }}>
                                    {item.value.toFixed(1)}
                                </span>
                            </div>
                        ))}
                    </div>
                </Card>
            )}

            {/* ── Tab 3: Year Comparison ────────────────────────────── */}
            {tab === 'Year Comparison' && (
                <Card>
                    <SectionTitle
                        title={`${group} Crimes · All Years · Top 15 States`}
                        sub="% change from 2017 to 2022 · Red = increased · Green = decreased"
                    />
                    <div style={{ overflowX: 'auto' }}>
                        <table style={{
                            width: '100%', borderCollapse: 'collapse', fontSize: 11,
                        }}>
                            <thead>
                                <tr style={{ background: '#0b1120' }}>
                                    <th style={{
                                        padding: '9px 12px', textAlign: 'left',
                                        color: '#64748b', fontWeight: 600,
                                        fontSize: 10, textTransform: 'uppercase',
                                        letterSpacing: 0.4,
                                    }}>
                                        State
                                    </th>
                                    {YEARS.map(yr => (
                                        <th key={yr} style={{
                                            padding: '9px 10px', textAlign: 'right',
                                            color: yr === year ? gc : '#64748b',
                                            fontWeight: yr === year ? 700 : 600,
                                            fontSize: 10, textTransform: 'uppercase',
                                        }}>
                                            {yr}
                                        </th>
                                    ))}
                                    <th style={{
                                        padding: '9px 10px', textAlign: 'right',
                                        color: '#64748b', fontWeight: 600,
                                        fontSize: 10, textTransform: 'uppercase',
                                    }}>
                                        Trend
                                    </th>
                                </tr>
                            </thead>
                            <tbody>
                                {ranked.slice(0, 15).map((item, i) => {
                                    const vals = YEARS.map(yr =>
                                        heatmapData[item.state]?.[group]?.[yr] || 0
                                    );
                                    const first = vals[0];
                                    const last = vals[vals.length - 1];
                                    const trend = first > 0
                                        ? ((last - first) / first * 100).toFixed(1)
                                        : null;
                                    const up = trend && parseFloat(trend) > 0;

                                    return (
                                        <tr key={item.state} style={{
                                            borderTop: '1px solid rgba(255,255,255,0.05)',
                                            background: i % 2 === 0
                                                ? 'transparent' : 'rgba(255,255,255,0.01)',
                                        }}>
                                            <td style={{
                                                padding: '8px 12px',
                                                color: '#94a3b8', fontSize: 11,
                                            }}>
                                                {item.state}
                                            </td>
                                            {vals.map((v, j) => (
                                                <td key={j} style={{
                                                    padding: '8px 10px', textAlign: 'right',
                                                    color: YEARS[j] === year ? gc : '#64748b',
                                                    fontWeight: YEARS[j] === year ? 700 : 400,
                                                    fontSize: 11,
                                                }}>
                                                    {v > 0 ? v.toFixed(1) : '—'}
                                                </td>
                                            ))}
                                            <td style={{
                                                padding: '8px 10px', textAlign: 'right',
                                                color: up ? '#f87171' : '#34d399',
                                                fontWeight: 700, fontSize: 11,
                                            }}>
                                                {trend
                                                    ? `${up ? '↑' : '↓'} ${Math.abs(parseFloat(trend))}%`
                                                    : '—'}
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                </Card>
            )}

            {/* ── Tooltip ───────────────────────────────────────────── */}
            {tooltip && tooltip.name && (
                <div style={{
                    position: 'fixed',
                    left: tooltip.x + 14,
                    top: tooltip.y - 50,
                    background: '#111827',
                    border: `1px solid ${gc}44`,
                    borderRadius: 8,
                    padding: '8px 14px',
                    pointerEvents: 'none',
                    zIndex: 9999,
                    minWidth: 160,
                }}>
                    <div style={{
                        fontSize: 12, fontWeight: 700,
                        color: gc, marginBottom: 3,
                    }}>
                        {tooltip.name}
                    </div>
                    <div style={{ fontSize: 10, color: '#64748b' }}>
                        {group} · {year}
                    </div>
                    <div style={{
                        fontSize: 15, fontWeight: 800,
                        color: '#f1f5f9', marginTop: 4,
                    }}>
                        {tooltip.value > 0
                            ? `${tooltip.value.toFixed(1)} avg crimes`
                            : 'No data'}
                    </div>
                </div>
            )}
        </Page>
    );
}
